#include <stdint.h>
#include <stdbool.h>

static inline void reg_set_bit(volatile uint32_t *reg, uint8_t bit) {
    *reg |= (1U << bit);
}

static inline void reg_clear_bit(volatile uint32_t *reg, uint8_t bit) {
    *reg &= ~(1U << bit);
}

static inline void reg_toggle_bit(volatile uint32_t *reg, uint8_t bit) {
    *reg ^= (1U << bit);
}

static inline bool reg_check_bit(volatile uint32_t *reg, uint8_t bit) {
    return (*reg & (1U << bit)) != 0;
}
```

**Key points:**
- Use `1U` (unsigned) to avoid undefined behavior when shifting into the sign bit
- `volatile` because these typically operate on hardware registers
- `static inline` for zero-overhead in headers
- Real codebases often use macros: `#define BIT(n) (1U << (n))`

